function u(){function n(t){return t==null?"R$ —":new Intl.NumberFormat("pt-BR",{style:"currency",currency:"BRL"}).format(t)}function r(t){return t?new Date(t+(t.length===10?"T00:00:00":"")).toLocaleDateString("pt-BR",{day:"2-digit",month:"2-digit",year:"numeric"}):"—"}function e(t){return t?new Date(t).toLocaleString("pt-BR",{day:"2-digit",month:"2-digit",year:"numeric",hour:"2-digit",minute:"2-digit"}):"—"}function i(t){return t==null?"0%":(t*100).toFixed(0)+"%"}return{formatMoney:n,formatDate:r,formatDateTime:e,formatPct:i}}export{u};
